import{_ as t,C as i,o as r,c as s,ag as o,E as c,w as l,a as n}from"./chunks/framework.BZohXCq9.js";const T=JSON.parse('{"title":"¿Qué es SYNTIcat?","description":"Catálogo digital con carrito de compras y checkout por WhatsApp","frontmatter":{"title":"¿Qué es SYNTIcat?","description":"Catálogo digital con carrito de compras y checkout por WhatsApp"},"headers":[],"relativePath":"cat/que-es-cat.md","filePath":"cat/que-es-cat.md"}'),d={name:"cat/que-es-cat.md"};function p(u,e,m,h,g,_){const a=i("Note");return r(),s("div",null,[e[1]||(e[1]=o('<p>SYNTIcat es el producto de SYNTIweb para negocios que venden <strong>productos físicos</strong> y necesitan un catálogo organizado con carrito de compras.</p><p>Tu cliente navega tu catálogo, agrega lo que quiere al carrito, y te envía el pedido completo por WhatsApp. Tú recibes la orden con todos los detalles y coordinas el pago y entrega como siempre.</p><h2 id="¿para-que-tipo-de-negocio-es" tabindex="-1">¿Para qué tipo de negocio es? <a class="header-anchor" href="#¿para-que-tipo-de-negocio-es" aria-label="Permalink to &quot;¿Para qué tipo de negocio es?&quot;">​</a></h2><ul><li>Tiendas de ropa y calzado</li><li>Boutiques y accesorios</li><li>Distribuidoras de productos</li><li>Tiendas de electrónica y tecnología</li><li>Negocios de cosméticos y cuidado personal</li><li>Emprendedores con catálogo de productos</li><li>Cualquier negocio donde el cliente elige de un catálogo</li></ul><h2 id="diferencia-con-studio-y-food" tabindex="-1">Diferencia con Studio y Food <a class="header-anchor" href="#diferencia-con-studio-y-food" aria-label="Permalink to &quot;Diferencia con Studio y Food&quot;">​</a></h2><p>SYNTIcat tiene carrito de compras. El cliente puede agregar varios productos, ver el total, y enviarte el pedido completo. Con Studio el cliente solo ve los productos pero no tiene carrito.</p><h2 id="el-sistema-de-ordenes-sc-xxxx" tabindex="-1">El sistema de órdenes SC-XXXX <a class="header-anchor" href="#el-sistema-de-ordenes-sc-xxxx" aria-label="Permalink to &quot;El sistema de órdenes SC-XXXX&quot;">​</a></h2><p>Cada pedido recibe un código único (ej: SC-0042). Tanto tú como el cliente tienen ese código para hacer seguimiento. Esto profesionaliza el proceso de ventas considerablemente.</p>',8)),c(a,null,{default:l(()=>[...e[0]||(e[0]=[n(" El carrito y el sistema de órdenes están disponibles en los planes Semestral y Anual. En el plan Básico el cliente puede escribirte por WhatsApp directamente desde cada producto. ",-1)])]),_:1}),e[2]||(e[2]=o('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/cat/que-es-synticat.html">¿Qué es SYNTIcat? (detallado)</a> — Planes, comparativa y ejemplo completo</li><li><a href="/cat/carrito-whatsapp.html">Carrito y WhatsApp</a> — Cómo funciona el checkout</li><li><a href="/cat/wizard-cat.html">Configurar tu catálogo</a> — El asistente de primeros pasos</li></ul>',2))])}const q=t(d,[["render",p]]);export{T as __pageData,q as default};
